from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# In-memory storage for labels
labels = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    # Store the label with annotator ID
    labels[image_id].append({'label': label, 'annotator_id': annotator_id})
    
    return jsonify({'message': 'Label received'}), 200

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    
    for image_id, label_data in labels.items():
        label_counts = defaultdict(int)
        
        for entry in label_data:
            label_counts[entry['label']] += 1
        
        # Majority voting
        majority_label = max(label_counts.items(), key=lambda x: x[1])[0]
        aggregated_labels[image_id] = majority_label
    
    return jsonify(aggregated_labels), 200

